void kernel_gpu_cuda_wrapper(
    record *records,
    long records_mem,
    knode *knodes,
    long knodes_elem,
    long knodes_mem,
    int order,
    long maxheight,
    int count,
    long *currKnode,
    long *offset,
    int *keys,
    record *ans)
{
    int threadsPerBlock = order < 1024 ? order : 1024;
    int blocksPerGrid = (count + threadsPerBlock - 1) / threadsPerBlock;

    record *d_records;
    knode *d_knodes;
    long *d_currKnode;
    long *d_offset;
    int *d_keys;
    record *d_ans;

    cudaMalloc(&d_records, records_mem);
    cudaMalloc(&d_knodes, knodes_mem);
    cudaMalloc(&d_currKnode, count * sizeof(long));
    cudaMalloc(&d_offset, count * sizeof(long));
    cudaMalloc(&d_keys, count * sizeof(int));
    cudaMalloc(&d_ans, count * sizeof(record));

    cudaMemcpy(d_records, records, records_mem, cudaMemcpyHostToDevice);
    cudaMemcpy(d_knodes, knodes, knodes_mem, cudaMemcpyHostToDevice);
    cudaMemcpy(d_currKnode, currKnode, count * sizeof(long), cudaMemcpyHostToDevice);
    cudaMemcpy(d_offset, offset, count * sizeof(long), cudaMemcpyHostToDevice);
    cudaMemcpy(d_keys, keys, count * sizeof(int), cudaMemcpyHostToDevice);

    kernel_cpu_cuda<<<blocksPerGrid, threadsPerBlock>>>(
        d_records,
        d_knodes,
        knodes_elem,
        order,
        maxheight,
        count,
        d_currKnode,
        d_offset,
        d_keys,
        d_ans);

    cudaMemcpy(ans, d_ans, count * sizeof(record), cudaMemcpyDeviceToHost);

    cudaFree(d_records);
    cudaFree(d_knodes);
    cudaFree(d_currKnode);
    cudaFree(d_offset);
    cudaFree(d_keys);
    cudaFree(d_ans);
}

